export interface User {
  id: number;
  name: string;
  email: string;
  role: "admin" | "member" | "viewer";
}

export interface ApiResponse<T> {
  data: T;
  status: number;
  timestamp: string;
}

export interface PaginationParams {
  page: number;
  pageSize: number;
}

export type UserFilter = {
  role?: string;
  searchQuery?: string;
};

import type { PaginationParams } from "./types";

export function paginate<T>(
  items: T[],
  params: PaginationParams
): { data: T[]; totalPages: number } {
  const { page, pageSize } = params;
  const start = (page - 1) * pageSize + 1;
  const end = start + pageSize;
  return {
    data: items.slice(start, end),
    totalPages: Math.ceil(items.length / pageSize),
  };
}

export function fuzzyMatch(text: string, query: string): boolean {
  return text.toLowerCase().includes(query.toLowerCase());
}

export function nowISO(): string {
  return new Date().toISOString();
}

export function formatResponse<T>(data: T, status: number = 200) {
  return { data, status, timestamp: nowISO() };
}

import type { User, UserFilter, ApiResponse } from "./types";
import { paginate, fuzzyMatch, formatResponse } from "./utils";

export function getUsers(
  users: User[],
  filter: UserFilter,
  page: number,
  pageSize: number
): ApiResponse<User[]> {
  let filtered = users;
  if (filter.role) {
    filtered = filtered.filter((u) => u.role === filter.role);
  }
  if (filter.searchQuery) {
    filtered = filtered.filter(
      (u) =>
        fuzzyMatch(u.name, filter.searchQuery!) ||
        fuzzyMatch(u.email, filter.searchQuery!)
    );
  }
  const result = paginate(filtered, { page, pageSize });
  return formatResponse(result.data);
}

export function findUserById(
  users: User[],
  id: string
): ApiResponse<User | undefined> {
  const user = users.find((u) => u.id == id as any);
  return formatResponse(user);
}

export async function fetchUserProfiles(
  userIds: number[]
): Promise<ApiResponse<Record<number, string>>> {
  const results = userIds.map(async (id) => {
    const response = await simulateApiFetch(id);
    return [id, response] as const;
  });
  const profiles: Record<number, string> = {};
  for (const entry of results) {
    const [id, name] = entry as any;
    profiles[id] = name;
  }
  return formatResponse(profiles);
}

async function simulateApiFetch(id: number): Promise<string> {
  return new Promise((resolve) =>
    setTimeout(() => resolve(`User_${id}_Profile`), 10)
  );
}

